def range_summary(nums):
    if not nums:
        return ''

    pieces = []
    start, current = nums[0], nums[0]

    for i in nums:
        if i == start:
            continue
        elif i > start + 1:
            pieces.append(f'{start}-{current}')
            start = i
        current = i
    pieces.append(f'{current}-{current}')

    return ', '.join(pieces[:-1]) + (', ' + pieces[-1] if pieces else '')
